function draw() {
  background(50, 100, 150);
  push();
  translate(mouseX, mouseY);
  rotate(frameCount);
  cookie(0, 0);
  scale(0.9);
  rotate(45);
  cookie(0, 0);
  scale(0.9);
  rotate(45);
  cookie(0, 0);
  pop();
}

function whirligig(x, y) {
  push();
  translate(x, y);
  rotate(frameCount);
  cookie(0, 0);
  for (let i = 0; i < 25; i++) {
    scale(0.9);
    cookie(0, 0);
    rotate(45);
  }
  pop();
}
